const SHEET_TAB_GIDS = {"content_queue":546012823,"content_drafts":299240858,"outreach_queue":1077351628,"video_drafts":532130684,"notification_events":160985613};

const APPROVAL_COL = {
  video_drafts: { status: 'Q', l3: 'S' },
  content_drafts: { status: 'K' },
  outreach_queue: { status: 'I', l3: 'J' },
};

function buildReviewUrl(sheetId, tab, row, approvalFields) {
  const base = `https://docs.google.com/spreadsheets/d/${sheetId}/edit`;
  const gid = SHEET_TAB_GIDS[tab];
  const cols = APPROVAL_COL[tab] || { status: 'A' };
  const fields = Array.isArray(approvalFields) ? approvalFields : [];
  const wantsL3 = fields.some((f) => String(f).toLowerCase().includes('l3_approved'));
  const col = wantsL3 && cols.l3 ? cols.l3 : cols.status || 'A';
  const r = Number(row) || 0;

  if (!gid) {
    return r > 1 ? `${base}#range=${col}${r}` : base;
  }
  if (r <= 1) {
    return `${base}#gid=${gid}`;
  }
  return `${base}#gid=${gid}&range=${col}${r}`;
}

const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const now = Date.now();
const sheet_tab = 'content_drafts';
const sheet_row = 2;
const approval_fields = ['status=approved'];

return [{
  json: {
    event_id: `manual:test:${now}:approval_needed`,
    event_type: 'approval_needed',
    agent: 'manual-test',
    severity: 'action_required',
    product_type: 'lead_magnet',
    target_channel: 'facebook_page',
    title: 'Magnix manual test — Telegram Notify',
    segment: 'noxh_income',
    source_row_key: 'manual:test',
    sheet_tab,
    sheet_row,
    approval_fields,
    review_url: buildReviewUrl(SHEET_ID, sheet_tab, sheet_row, approval_fields),
    preview_url: '',
    due_at: new Date(Date.now() + 2 * 3600000).toISOString(),
    telegram_enabled: String($env.TELEGRAM_APPROVAL_ENABLED || '').toLowerCase() === 'true',
    bot_token_set: String($env.TELEGRAM_BOT_TOKEN || '').length > 10,
    chat_id: $env.TELEGRAM_CHAT_ID_OWNER || $env.TELEGRAM_CHAT_ID_OPS || '',
  },
}];

// Inlined vào n8n Code nodes — build deep link tới cột duyệt L3
// Placeholder {"content_queue":546012823,"content_drafts":299240858,"outreach_queue":1077351628,"video_drafts":532130684,"notification_events":160985613} được thay lúc build workflow.

const SHEET_TAB_GIDS = {"content_queue":546012823,"content_drafts":299240858,"outreach_queue":1077351628,"video_drafts":532130684,"notification_events":160985613};

const APPROVAL_COL = {
  video_drafts: { status: 'Q', l3: 'S' },
  content_drafts: { status: 'K' },
  outreach_queue: { status: 'I', l3: 'J' },
};

function buildReviewUrl(sheetId, tab, row, approvalFields) {
  const base = `https://docs.google.com/spreadsheets/d/${sheetId}/edit`;
  const gid = SHEET_TAB_GIDS[tab];
  const cols = APPROVAL_COL[tab] || { status: 'A' };
  const fields = Array.isArray(approvalFields) ? approvalFields : [];
  const wantsL3 = fields.some((f) => String(f).toLowerCase().includes('l3_approved'));
  const col = wantsL3 && cols.l3 ? cols.l3 : cols.status || 'A';
  const r = Number(row) || 0;

  if (!gid) {
    return r > 1 ? `${base}#range=${col}${r}` : base;
  }
  if (r <= 1) {
    return `${base}#gid=${gid}`;
  }
  return `${base}#gid=${gid}&range=${col}${r}`;
}

const EXPECTED = $env.MAGNIX_WEBHOOK_TOKEN || '';
const headers = $input.first().json.headers || {};
const auth = headers.authorization || headers.Authorization || '';
if (EXPECTED && auth !== `Bearer ${EXPECTED}`) {
  throw new Error('Unauthorized: invalid MAGNIX_WEBHOOK_TOKEN');
}

const raw = $input.first().json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;

const event_id = String(body.event_id || '').trim();
if (!event_id) throw new Error('Validation: event_id is required');

const event_type = String(body.event_type || 'approval_needed').trim();
const agent = String(body.agent || body.source_workflow || 'unknown').trim();
const title = String(body.title || '(no title)').slice(0, 120);
const segment = String(body.segment || '').slice(0, 40);
const sheet_tab = String(body.sheet_tab || body.target_tab || '').trim();
const sheet_row = Number(body.sheet_row || 0);
const product_type = String(body.product_type || '').slice(0, 60);
const target_channel = String(body.target_channel || '').slice(0, 40);
const preview_url = String(body.preview_url || '').slice(0, 500);
const source_row_key = String(body.source_row_key || body.source_key || '').slice(0, 120);
const approval_fields = Array.isArray(body.approval_fields) ? body.approval_fields : [];

const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const review_url = sheet_tab
  ? buildReviewUrl(SHEET_ID, sheet_tab, sheet_row, approval_fields)
  : String(body.review_url || '').slice(0, 500);

const due_at = body.due_at || new Date(Date.now() + 2 * 3600000).toISOString();
const chat_id = $env.TELEGRAM_CHAT_ID_OWNER || $env.TELEGRAM_CHAT_ID_OPS || '';

return [{
  json: {
    event_id,
    event_type,
    agent,
    severity: String(body.severity || 'action_required'),
    title,
    segment,
    product_type,
    target_channel,
    sheet_tab,
    sheet_row,
    source_row_key,
    review_url,
    preview_url,
    approval_fields,
    due_at,
    telegram_enabled: String($env.TELEGRAM_APPROVAL_ENABLED || '').toLowerCase() === 'true',
    bot_token_set: String($env.TELEGRAM_BOT_TOKEN || '').length > 10,
    chat_id,
  },
}];

const item = $input.first().json;
const approval = (item.approval_fields || []).join(' + ') || 'approve / reject trên Sheet';
const now = new Date().toISOString();

let header = '[Magnix]';
if (item.event_type === 'approval_needed') header = '[Magnix] Cần duyệt L3';
else if (item.event_type === 'render_review_needed') header = '[Magnix] Cần xem bản dựng video';
else if (item.event_type === 'legal_source_needed') header = '[Magnix] Cần bổ sung căn cứ pháp lý';
else if (item.event_type === 'workflow_blocked') header = '[Magnix] Workflow bị block';
else if (item.event_type === 'qa_failed') header = '[Magnix] QA fail — cần sửa';
else if (item.event_type === 'metrics_needed') header = '[Magnix] Thiếu metrics';
else if (item.event_type === 'publish_ready') header = '[Magnix] Sẵn sàng đăng';

const lines = [
  header,
  `Agent: ${item.agent}`,
  `Loại: ${item.product_type || item.event_type}${item.target_channel ? ` → ${item.target_channel}` : ''}`,
  `Tiêu đề: ${item.title}`,
];

if (item.segment) lines.push(`Segment: ${item.segment}`);
if (item.sheet_tab) {
  lines.push(
    item.sheet_row
      ? `Dòng: ${item.sheet_tab} row ${item.sheet_row}`
      : `Tab: ${item.sheet_tab}`
  );
}
if (item.event_type === 'approval_needed' || item.event_type === 'legal_source_needed') {
  lines.push(`Cần làm: ${approval}`);
  lines.push('Trên Sheet: dùng dropdown cột status (draft/approved/rejected). Video & outreach: tick ☑ l3_approved.');
}
if (item.preview_url) lines.push(`Preview: ${item.preview_url}`);
if (item.review_url) {
  lines.push(`👉 Mở duyệt (nhảy đúng tab + cột): ${item.review_url}`);
}
if (item.due_at) lines.push(`Hạn xử lý: ${item.due_at}`);

const message = lines.join('\n').slice(0, 3900);

const meta = JSON.stringify({
  severity: item.severity,
  title: item.title,
  segment: item.segment,
  product_type: item.product_type,
  target_channel: item.target_channel,
  sheet_row: item.sheet_row,
  review_url: item.review_url,
  preview_url: item.preview_url,
  approval_fields: item.approval_fields || [],
  due_at: item.due_at,
  reminder_count: 0,
  last_reminded_at: null,
  agent: item.agent,
}).slice(0, 45000);

return [{
  json: {
    ...item,
    message,
    created_at: now,
    append_row: [
      item.event_id,
      item.event_type,
      item.agent,
      item.source_row_key || `row_${item.sheet_row || 0}`,
      item.sheet_tab,
      'pending',
      message,
      '',
      '',
      now,
      '',
      meta,
    ],
  },
}];

const item = $('Format Message').item?.json || $input.first().json;
const getRes = $input.first().json || {};
const rows = getRes.values || [];

const existingIds = new Set();
for (const row of rows) {
  const id = String(row[0] || '').trim();
  const status = String(row[5] || '').trim().toLowerCase();
  if (id && ['sent', 'reminded', 'pending'].includes(status)) {
    existingIds.add(id);
  }
}

if (existingIds.has(item.event_id)) {
  return [{
    json: {
      ...item,
      duplicate: true,
      skipped: true,
      ok: true,
      reason: 'DUPLICATE_EVENT_ID',
    },
  }];
}

return [{
  json: {
    ...item,
    duplicate: false,
    skipped: false,
    append_body: { values: [item.append_row] },
  },
}];

const item = $('Dedupe Check').item?.json || {};
const postRes = $input.first().json || {};

let sheet_row = null;
const range = postRes?.updates?.updatedRange || '';
const m = range.match(/!(?:[A-Z]+)(\d+):/i);
if (m) sheet_row = Number(m[1]);

return [{
  json: {
    ...item,
    sheet_logged: true,
    sheet_row,
    duplicate: false,
    skipped: false,
  },
}];

const item = $input.first().json;
if (item.duplicate || item.skipped) {
  return [{ json: { ...item, telegram_sent: false, telegram_skip: item.reason || 'duplicate' } }];
}

if (!item.telegram_enabled) {
  return [{ json: { ...item, telegram_sent: false, telegram_skip: 'TELEGRAM_APPROVAL_ENABLED' } }];
}

const token = $env.TELEGRAM_BOT_TOKEN || '';
const chatId = item.chat_id || '';
if (!token || !chatId) {
  return [{
    json: {
      ...item,
      telegram_sent: false,
      telegram_skip: 'MISSING_BOT_TOKEN_OR_CHAT_ID',
      sheet_status: 'failed',
    },
  }];
}

let tgRes;
try {
  tgRes = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${token}/sendMessage`,
    body: {
      chat_id: chatId,
      text: item.message,
      disable_web_page_preview: false,
    },
    json: true,
    timeout: 15000,
  });
} catch (e) {
  return [{
    json: {
      ...item,
      telegram_sent: false,
      telegram_error: e.message || 'TELEGRAM_HTTP_FAIL',
      sheet_status: 'failed',
    },
  }];
}

const messageId = tgRes?.result?.message_id ? String(tgRes.result.message_id) : '';
const chatIdOut = tgRes?.result?.chat?.id ? String(tgRes.result.chat.id) : chatId;

return [{
  json: {
    ...item,
    telegram_sent: Boolean(tgRes?.ok),
    telegram_message_id: messageId,
    telegram_chat_id: chatIdOut,
    sheet_status: tgRes?.ok ? 'sent' : 'failed',
  },
}];

const item = $input.first().json;
const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const TAB = 'notification_events';

if (!item.sheet_logged || item.duplicate || item.skipped || !item.sheet_row) {
  return [{
    json: {
      ok: item.ok !== false,
      event_id: item.event_id,
      event_type: item.event_type,
      telegram_sent: item.telegram_sent === true,
      duplicate: item.duplicate === true,
      skipped: item.skipped === true,
      reason: item.reason || item.telegram_skip || item.telegram_error || null,
      sheet_row: item.sheet_row || null,
      finished_at: new Date().toISOString(),
    },
  }];
}

const status = item.sheet_status || (item.telegram_sent ? 'sent' : 'failed');
const row = item.sheet_row;

return [{
  json: {
    ...item,
    put_url: `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${encodeURIComponent(`${TAB}!F${row}:I${row}`)}?valueInputOption=USER_ENTERED`,
    put_body: {
      values: [[status, item.message, item.telegram_chat_id || '', item.telegram_message_id || '']],
    },
    response: {
      ok: item.ok !== false,
      event_id: item.event_id,
      event_type: item.event_type,
      telegram_sent: item.telegram_sent === true,
      duplicate: false,
      skipped: false,
      reason: item.telegram_error || null,
      sheet_row: row,
      sheet_status: status,
      finished_at: new Date().toISOString(),
    },
  },
}];

const item = $input.first().json;
const prep = $('Prepare Status PUT').item?.json;

if (prep?.response) {
  return [{ json: prep.response }];
}

if (item.skipped || item.duplicate) {
  return [{
    json: {
      ok: true,
      event_id: item.event_id,
      event_type: item.event_type,
      telegram_sent: false,
      duplicate: true,
      skipped: true,
      reason: item.reason || 'DUPLICATE_EVENT_ID',
      finished_at: new Date().toISOString(),
    },
  }];
}

return [{ json: item }];
